import * as React from 'react';

import * as TogglePrimitive from '@radix-ui/react-toggle';
import { type VariantProps } from 'class-variance-authority';

import { CheckIcon, IndeterminateCheckIcon } from '../icons';
import { cn } from '../utils/cn';
import { toggleVariants } from './common/variants';

export type ToggleIndicatorProps = React.ComponentProps<'div'> & {
  indeterminate?: boolean;
};

/**
 * Visual indicator for toggles.
 *
 * Currently the only variant is a checkbox-style indicator. We may wish to
 * extend to provide a radio-button visual variant in future.
 */
function ToggleIndicator({
  className,
  children,
  indeterminate = false,
  ...props
}: ToggleIndicatorProps) {
  const content =
    children ||
    (indeterminate ? (
      <IndeterminateCheckIcon className="text-primary-foreground" />
    ) : (
      <CheckIcon className="text-transparent group-data-[state=on]/toggle:text-background" />
    ));
  return (
    <div
      className={cn(
        'inline-flex size-4 items-center justify-center rounded-sm border border-input transition-colors',
        'group-data-[state=on]/toggle:border-primary group-data-[state=on]/toggle:bg-primary',
        'data-[indeterminate=true]:border-primary data-[indeterminate=true]:bg-primary',
        className
      )}
      data-indeterminate={indeterminate}
      {...props}
    >
      {content}
    </div>
  );
}

/**
 * A two-state button that can be either on or off.
 */
function Toggle({
  className,
  size,
  children,
  ...props
}: React.ComponentProps<typeof TogglePrimitive.Root> &
  VariantProps<typeof toggleVariants>) {
  return (
    <TogglePrimitive.Root
      data-slot="toggle"
      className={cn('group/toggle', toggleVariants({ size, className }))}
      {...props}
    >
      {children}
    </TogglePrimitive.Root>
  );
}

export { Toggle, ToggleIndicator };
